import{_ as r,o as e,c as a,ae as l}from"./chunks/framework.DAK3ioSj.js";const b=JSON.parse('{"title":"Skills 业界代表项目调研","description":"","frontmatter":{},"headers":[],"relativePath":"radar/02-projects.md","filePath":"radar/02-projects.md"}'),d={name:"radar/02-projects.md"};function o(h,t,n,s,i,g){return e(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="skills-业界代表项目调研" tabindex="-1">Skills 业界代表项目调研 <a class="header-anchor" href="#skills-业界代表项目调研" aria-label="Permalink to &quot;Skills 业界代表项目调研&quot;">​</a></h1><blockquote><p><strong>版本</strong>: v2.1 · <strong>更新日期</strong>: 2026-05-12</p><p>本表列出业界 <strong>24 个</strong>有公开论文 / 仓库 / 产品页可验证的真实方案。所有条目均不是占位，所有数字均经过两轮事实核查。</p><p>★ = 2026-05 调研新增条目（ACE / SkillRL / SkillRet / SkCC / Vercel skills.sh）</p></blockquote><hr><h2 id="_1-skill-生成-generation" tabindex="-1">1. Skill 生成（Generation） <a class="header-anchor" href="#_1-skill-生成-generation" aria-label="Permalink to &quot;1. Skill 生成（Generation）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目 / 论文</th><th>来源</th><th>核心技术</th><th>链接</th></tr></thead><tbody><tr><td><strong>Skill Creator</strong></td><td>Anthropic 官方</td><td>引导式 + Eval 闭环 + description 自动优化</td><td><a href="https://docs.claude.com/en/docs/agents-and-tools/agent-skills" target="_blank" rel="noreferrer">Anthropic Docs</a> · <a href="./tech-skill-creator.html">详情</a></td></tr><tr><td><strong>Skill Seekers</strong></td><td>社区 (13.4K+ ★)</td><td>18 数据源 → 20 目标平台自动适配</td><td><a href="https://github.com/yusufkaraaslan/Skill_Seekers" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skill-seekers.html">详情</a></td></tr><tr><td><strong>EvoSkill</strong></td><td>Sentient AGI (726 ★)</td><td>三 Agent 协作从失败中自动发现 Skill；+7.3% OfficeQA / +12.1% SealQA</td><td><a href="https://arxiv.org/abs/2603.02766" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/sentient-agi/EvoSkill" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-evoskill.html">详情</a></td></tr><tr><td><strong>EvoSkills / CoEvoSkills</strong></td><td>学术</td><td>Surrogate Verifier + Oracle 协同进化（75% 通过率）</td><td><a href="https://arxiv.org/abs/2604.01687" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/Zhang-Henry/CoEvoSkills" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-evoskills.html">详情</a></td></tr><tr><td><strong>Claudeception</strong></td><td>社区 (<strong>2.3K+ ★</strong>)</td><td>Claude Code 会话自动提取「可复用 + 非平凡 + 具体 + 已验证」Skill</td><td><a href="https://github.com/blader/Claudeception" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-claudeception.html">详情</a></td></tr><tr><td><strong>Trace2Skill</strong></td><td>阿里 Qwen + ETH</td><td>并行多 sub-agent 编队从轨迹池蒸馏 Skill</td><td><a href="https://arxiv.org/abs/2603.25158" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-trace2skill.html">详情</a></td></tr><tr><td><strong>SkillForge</strong></td><td>工业研究 (SIGIR 2026)</td><td>从历史工单挖掘工具 schema + 三阶段自优化</td><td><a href="https://arxiv.org/abs/2604.08618" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillforge.html">详情</a></td></tr><tr><td><strong>SkillX</strong></td><td>学术</td><td>策略 / 功能 / 原子三层粒度蒸馏</td><td><a href="https://arxiv.org/abs/2604.04804" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillx.html">详情</a></td></tr><tr><td><strong>SkillRL</strong> ★</td><td>aiming-lab</td><td>经验蒸馏 + 自适应检索 + Skill 库与 RL 策略递归共进化</td><td><a href="https://arxiv.org/abs/2602.08234" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/aiming-lab/SkillRL" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skillrl.html">详情</a></td></tr></tbody></table><hr><h2 id="_2-skill-召回-recall-routing" tabindex="-1">2. Skill 召回（Recall / Routing） <a class="header-anchor" href="#_2-skill-召回-recall-routing" aria-label="Permalink to &quot;2. Skill 召回（Recall / Routing）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目 / 论文</th><th>来源</th><th>核心技术</th><th>链接</th></tr></thead><tbody><tr><td><strong>SkillRouter</strong></td><td>学术</td><td>双编码器 + 重排，80K 池 74% Hit@1，1.2B 模型 13× 少参数、5.8× 更快</td><td><a href="https://arxiv.org/abs/2603.22455" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/zhengyanzhao1997/SkillRouter" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skillrouter.html">详情</a></td></tr><tr><td><strong>AgentSkillOS</strong></td><td>学术</td><td>Capability Tree 递归分类 + DAG 编排</td><td><a href="https://arxiv.org/abs/2603.02176" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-agentskillos.html">详情</a></td></tr><tr><td><strong>SkillNet</strong></td><td>浙大 NLP (735 ★)</td><td>200K+ Skill 仓库 + Ontology 三层架构</td><td><a href="https://arxiv.org/abs/2603.04448" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/zjunlp/SkillNet" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skillnet.html">详情</a></td></tr><tr><td><strong>SkillRouter.org</strong></td><td>商业（早期）</td><td>MCP 路由服务（落地页阶段）</td><td><a href="https://skillrouter.org/" target="_blank" rel="noreferrer">官网</a> · <a href="./tech-skillrouter-org.html">详情</a></td></tr></tbody></table><hr><h2 id="_3-skill-执行-execution" tabindex="-1">3. Skill 执行（Execution） <a class="header-anchor" href="#_3-skill-执行-execution" aria-label="Permalink to &quot;3. Skill 执行（Execution）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目 / 论文</th><th>来源</th><th>核心技术</th><th>链接</th></tr></thead><tbody><tr><td><strong>OpenSpace</strong></td><td>HKU (<strong>6.1K+ ★</strong>)</td><td>MCP Server 即插即用接入 Claude Code / Codex / Cursor</td><td><a href="https://github.com/HKUDS/OpenSpace" target="_blank" rel="noreferrer">GitHub</a> · <a href="https://open-space.cloud/" target="_blank" rel="noreferrer">社区云</a> · <a href="./tech-openspace.html">详情</a></td></tr><tr><td><strong>AgentSkillOS</strong></td><td>学术</td><td>DAG 编排，能并行的并行、必须串行的串行</td><td><a href="https://arxiv.org/abs/2603.02176" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-agentskillos.html">详情</a></td></tr><tr><td><strong>Memento-Skills</strong></td><td>学术 (1.4K+ ★)</td><td>Read → Execute → Reflect → Write 闭环</td><td><a href="https://arxiv.org/abs/2603.18743" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/Memento-Teams/Memento-Skills" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-memento-skills.html">详情</a></td></tr><tr><td><strong>SkCC</strong> ★</td><td>学术</td><td>SkIR 强类型 IR：跨 Agent 框架可移植部署（Claude Code +12.2pp / Kimi CLI +13.6pp）</td><td><a href="https://arxiv.org/abs/2605.03353" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skcc.html">详情</a></td></tr></tbody></table><hr><h2 id="_4-skill-评测-evaluation" tabindex="-1">4. Skill 评测（Evaluation） <a class="header-anchor" href="#_4-skill-评测-evaluation" aria-label="Permalink to &quot;4. Skill 评测（Evaluation）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目 / 论文</th><th>来源</th><th>核心技术</th><th>链接</th></tr></thead><tbody><tr><td><strong>SkillsBench</strong></td><td>学术 (1.2K+ ★)</td><td>三条件对比，7,308 条轨迹 / 84 任务 / 11 领域</td><td><a href="https://arxiv.org/abs/2602.12670" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/benchflow-ai/skillsbench" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skillsbench.html">详情</a></td></tr><tr><td><strong>SkillNet 5 维评分</strong></td><td>浙大 NLP</td><td>安全 / 完整 / 可执行 / 可维护 / 成本</td><td><a href="https://arxiv.org/abs/2603.04448" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillnet.html">详情</a></td></tr><tr><td><strong>EvoSkills Surrogate Verifier</strong></td><td>学术</td><td>主动生成测试断言 + 结构化失败诊断反馈</td><td><a href="https://arxiv.org/abs/2604.01687" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-evoskills.html">详情</a></td></tr><tr><td><strong>SkillForge Diagnostician</strong></td><td>工业研究 (SIGIR 2026)</td><td>将执行失败追溯回具体 Skill 缺陷</td><td><a href="https://arxiv.org/abs/2604.08618" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillforge.html">详情</a></td></tr><tr><td><strong>SkillRet</strong> ★</td><td>学术</td><td>Skill 检索大规模基准：17,810 Skill / 63K 训练 / 5K 评测，NDCG@10 +13.1</td><td><a href="https://arxiv.org/abs/2605.05726" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillret.html">详情</a></td></tr></tbody></table><hr><h2 id="_5-skill-优化-optimization" tabindex="-1">5. Skill 优化（Optimization） <a class="header-anchor" href="#_5-skill-优化-optimization" aria-label="Permalink to &quot;5. Skill 优化（Optimization）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目 / 论文</th><th>来源</th><th>核心技术</th><th>链接</th></tr></thead><tbody><tr><td><strong>OpenSpace</strong></td><td>HKU (<strong>6.1K+ ★</strong>)</td><td>FIX / DERIVED / CAPTURED 三模式实时进化</td><td><a href="https://github.com/HKUDS/OpenSpace" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-openspace.html">详情</a></td></tr><tr><td><strong>ACE</strong> ★</td><td>Stanford 等 (ICLR 2026)</td><td>Generation / Reflection / Curation 三阶段 context engineering</td><td><a href="https://arxiv.org/abs/2510.04618" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-ace.html">详情</a></td></tr><tr><td><strong>Hermes Self-Evolution</strong></td><td>Nous Research (3.1K+ ★)</td><td>GEPA 优化器（ICLR 2026 接收）+ PR 模式人工审核</td><td><a href="https://github.com/NousResearch/hermes-agent-self-evolution" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-hermes-self-evolution.html">详情</a></td></tr><tr><td><strong>SkillClaw</strong></td><td>AMAP-ML (1.3K+ ★)</td><td>后台守护进程聚合多用户轨迹进化 Skill</td><td><a href="https://arxiv.org/abs/2604.08377" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/AMAP-ML/SkillClaw" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skillclaw.html">详情</a></td></tr><tr><td><strong>MetaClaw</strong></td><td>OpenClaw (3.4K+ ★)</td><td>Fast Loop（秒级）+ Slow Loop（小时级）双环</td><td><a href="https://arxiv.org/abs/2603.17187" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/aiming-lab/MetaClaw" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-metaclaw.html">详情</a></td></tr><tr><td><strong>SkillReducer</strong></td><td>港科大</td><td>静态压缩 + 渐进披露，less-is-more 效应 +2.8%</td><td><a href="https://arxiv.org/abs/2603.29919" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillreducer.html">详情</a></td></tr><tr><td><strong>EvoSkill (Pareto)</strong></td><td>Sentient AGI (726 ★)</td><td>Pareto 前沿选择 + Git 分支管理进化变体</td><td><a href="https://arxiv.org/abs/2603.02766" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-evoskill.html">详情</a></td></tr><tr><td><strong>SkillForge (Optimizer)</strong></td><td>工业研究 (SIGIR 2026)</td><td>Failure Analyzer → Diagnostician → Optimizer</td><td><a href="https://arxiv.org/abs/2604.08618" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillforge.html">详情</a></td></tr><tr><td><strong>SkillRL</strong> ★</td><td>aiming-lab</td><td>Skill 库与 RL 策略递归共进化</td><td><a href="https://arxiv.org/abs/2602.08234" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-skillrl.html">详情</a></td></tr></tbody></table><hr><h2 id="_6-skill-管理-management" tabindex="-1">6. Skill 管理（Management） <a class="header-anchor" href="#_6-skill-管理-management" aria-label="Permalink to &quot;6. Skill 管理（Management）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目 / 论文</th><th>来源</th><th>核心技术</th><th>链接</th></tr></thead><tbody><tr><td><strong>Vercel skills.sh</strong> ★</td><td>Vercel (2026-01)</td><td>工业级 Skill 注册中心 + 排行榜</td><td><a href="https://skills.sh/" target="_blank" rel="noreferrer">官网</a> · <a href="https://github.com/vercel-labs/skills" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skills-sh.html">详情</a></td></tr><tr><td><strong>SkillNet</strong></td><td>浙大 NLP (735 ★)</td><td>200K+ Skill 集中式知识库</td><td><a href="https://arxiv.org/abs/2603.04448" target="_blank" rel="noreferrer">论文</a> · <a href="https://github.com/zjunlp/SkillNet" target="_blank" rel="noreferrer">GitHub</a> · <a href="./tech-skillnet.html">详情</a></td></tr><tr><td><strong>AgentSkillOS</strong></td><td>学术</td><td>生态级生命周期管理</td><td><a href="https://arxiv.org/abs/2603.02176" target="_blank" rel="noreferrer">论文</a> · <a href="./tech-agentskillos.html">详情</a></td></tr><tr><td><strong>Agent Skills 标准</strong></td><td>社区开放标准（Anthropic 发起）</td><td>跨平台 Skill 格式与协议，~38+ 产品采用</td><td><a href="https://agentskills.io/" target="_blank" rel="noreferrer">官网</a> · <a href="./tech-skills-standard.html">详情</a></td></tr></tbody></table><hr><h2 id="关于-我们的能力" tabindex="-1">关于&quot;我们的能力&quot; <a class="header-anchor" href="#关于-我们的能力" aria-label="Permalink to &quot;关于&quot;我们的能力&quot;&quot;">​</a></h2><p>本文档<strong>只列业界产品</strong>。本团队（基于 skill-insight 全生命周期管理方法论）自研的差异化能力（如 Agent 过程遵从性评测、多维度观测看板、Skill 多版本管理及趋势观测）<strong>不在此页范围</strong>。</p>',23)])])}const f=r(d,[["render",o]]);export{b as __pageData,f as default};
